#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    char username[101];
    int score;
} Pair;

int cmpDesc(const void *a, const void *b) {
    const Pair *p1 = (const Pair *)a;
    const Pair *p2 = (const Pair *)b;
    return p2->score - p1->score; // descending by score
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        Pair *arr = (Pair *)malloc(N * sizeof(Pair));
        for (int i = 0; i < N; ++i) {
            scanf("%100s %d", arr[i].username, &arr[i].score);
        }
        qsort(arr, N, sizeof(Pair), cmpDesc);
        for (int i = 0; i < N; ++i) {
            printf("%s: %d\n", arr[i].username, arr[i].score);
        }
        free(arr);
    }
    return 0;
}

