    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int N; cin>>N;
        vector<Pair> v(N);
        for(int i=0;i<N;++i) cin>>v[i].username>>v[i].score;
