        for(const auto& p: v) cout<<p.username<<": "<<p.score<<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static class Pair {
        String username;
        int score;
        Pair(String u, int s) { username = u; score = s; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            List<Pair> list = new ArrayList<>(N);
            for (int i = 0; i < N; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                list.add(new Pair(st.nextToken(), Integer.parseInt(st.nextToken())));
            }
            list.sort((a, b) -> Integer.compare(b.score, a.score));
            for (Pair p : list) {
                out.append(p.username).append(": ").append(p.score).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        pairs = []
        for _ in range(N):
            username, score = next(it).split()
            pairs.append((username, int(score)))
        pairs.sort(key=lambda x: x[1], reverse=True)
        for u, s in pairs:
            out.append(f"{u}: {s}")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

